  ('optometrist-moex-00947', 'optometrist', 'optometrist-moex-111-ddcf1380', 'sub-optometrist-04', NULL, 'single_choice', '關於眼球屈光系統，下列敘述何者正確？①水晶體前表面曲率半徑較後表面大  ②水晶體前表面曲率半徑', '["水晶體後表面屈光效果為會聚光線（convergence）", "水晶體後表面屈光效果為發散光線 （divergence）", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:44+00:00", "source_pdf_sha1": "02b2f4655967", "answer_pdf_sha1": "3ad9719516e3", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "111", "s": "1002", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視覺光學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 31, "answer_corrected": true, "flags": ["answer_corrected_skip_v1", "incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
